1	// Integration tests for the pack-system HD2 bundle end-to-end.
2	//
3	// Covers: Pack serialisation round-trip, flatten, export/import (ZIP), ProfileManager
4	// persistence, and a realistic Helldivers-2 stratagem macro-pack fixture that exercises
5	// every field of MacroConfig (phrase, if_flag, set_flag, sound, keys with dwell/gap
6	// overrides).  All tests are hermetic — no XDG writes, no network, no model files.
7	
8	use std::io::Write;
9	
10	use serial_test::serial;
11	use vibe_attack::{
12	    config::{KeyAction, MacroConfig},
13	    pack::{Category, Pack},
14	    pack::manager::ProfileManager,
15	};
