21	fn key(name: &str) -> KeyAction {
22	    KeyAction { key: name.to_string(), dwell_ms: None, gap_ms: None }
23	}
24	
25	fn key_timed(name: &str, dwell_ms: u64, gap_ms: u64) -> KeyAction {
26	    KeyAction { key: name.to_string(), dwell_ms: Some(dwell_ms), gap_ms: Some(gap_ms) }
27	}
