29	fn macro_simple(name: &str, phrase: &str, keys: Vec<KeyAction>) -> MacroConfig {
30	    MacroConfig {
31	        name: name.to_string(),
32	        phrase: Some(phrase.to_string()),
33	        if_flag: None,
34	        set_flag: None,
35	        sound: None,
36	        keys,
37	    }
38	}
