40	fn macro_with_flags(
41	    name: &str,
42	    phrase: &str,
43	    if_flag: Option<&str>,
44	    set_flag: Option<&str>,
45	    keys: Vec<KeyAction>,
46	) -> MacroConfig {
47	    MacroConfig {
48	        name: name.to_string(),
49	        phrase: Some(phrase.to_string()),
50	        if_flag: if_flag.map(str::to_string),
51	        set_flag: set_flag.map(str::to_string),
52	        sound: None,
53	        keys,
54	    }
